//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: **CT_OnOff boolean property value-domain and present-means-true semantics**.
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 about how Word consumes (and how the stemma
//! serializer must re-emit) `CT_OnOff` boolean properties:
//!   - a bare child element (no `@val`) is **present-means-true** (ON);
//!   - `@val="0"|"false"|"off"` is the **explicit-off** false literal;
//!   - `@val="1"|"true"|"on"` is the **explicit-on** true literal;
//!   - the transitional `ST_OnOff` union admits the `on`/`off` ST_OnOff1 spellings,
//!     the strict union admits only the `xsd:boolean` lexicals (`1`/`0`/`true`/`false`);
//!   - an attribute-carried CT_OnOff value (e.g. `fldSimple/@dirty`) is the
//!     *opposite* tri-state: **omission is assumed false**.
//!
//! A **FAIL here encodes a real Word-compliance gap** in stemma (the engine
//! diverges from how Word reads/writes the property). Do NOT weaken an
//! assertion to make it green — a failure is the finding we are hunting.
//!
//! METHODOLOGY (consumption vs. save): stemma round-trips untouched content
//! byte-verbatim. So `xml*` assertions on `reserialize()` of an *unedited* doc
//! are valid only for markup the serializer actively generates/restructures.
//! The value-domain `xml*` specs below target exactly that: the model-driven
//! re-emission of a toggle element. Consumption semantics ("off means off",
//! "present means true") are asserted on the read side (accept/reject text) or
//! via opens-clean validity.

use std::io::Read;

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude: zip plumbing ───────────────────────────────────────────────────

/// Build a minimal valid `.docx`. `body_xml` is the inner content of
/// `<w:body>…</w:body>` (paragraphs, sectPr, …). `extra_parts` is a list of
/// `(part_name, xml)` written verbatim into the zip; each non-document part also
/// gets a `[Content_Types].xml` override based on its file name.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for any extra parts we recognise.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let ct = if part.ends_with("styles.xml") {
            Some("application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml")
        } else if part.ends_with("numbering.xml") {
            Some("application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml")
        } else {
            None
        };
        if let Some(ct) = ct {
            overrides.push_str(&format!(
                r#"<Override PartName="/{part}" ContentType="{ct}"/>"#
            ));
        }
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return `word/document.xml` as a string.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse → serialize(default) → `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Extract the substring of `xml` for the first occurrence of a start-tag whose
/// opening text begins with `open` (e.g. `"<w:widowControl"`), up to its closing
/// `>`. Used to scope an `xmlRegex`-style `val=` check to the right element.
/// Returns `None` if absent.
fn start_tag(xml: &str, open: &str) -> Option<String> {
    let start = xml.find(open)?;
    let rest = &xml[start..];
    let end = rest.find('>')?;
    Some(rest[..=end].to_string())
}

/// True if the start-tag text carries an explicit-off `w:val` (0/false/off).
fn tag_has_explicit_off(tag: &str) -> bool {
    tag.contains(r#"w:val="0""#)
        || tag.contains(r#"w:val="false""#)
        || tag.contains(r#"w:val="off""#)
}

