/// CT_OnOff carried as an attribute (fldSimple/@dirty): omission is assumed
/// FALSE (MS-OI29500 §3.1.3, §2.1.1744), the opposite of present-means-true for
/// child elements. stemma must open clean and never fabricate dirty="true".
#[test]
fn onoff_attribute_dirty_omitted_defaults_false_not_present_means_true() {
    let body = r#"<w:p><w:fldSimple w:instr="AUTHOR"><w:r><w:t>Rex Jaeschke</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "opensClean — ISO 29500-1 §17.16.19, MS-OI29500 §3.1.3.3.6: fldSimple with @dirty \
         omitted is schema-valid (dirty is an optional ST_OnOff attribute); Word opens it \
         without repair. Validator issues: {:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted");
    assert_eq!(
        accepted.to_text().trim(),
        "Rex Jaeschke",
        "acceptTextEquals — MS-OI29500 §3.1.3, ISO 29500-1 §17.16.19, §22.9.2.7: an omitted \
         @dirty is assumed false (not stale); accept-all reproduces the cached field result \
         text verbatim. A fabricated dirty=\"true\" would mark every field stale to Word."
    );
}

/// Bare <w:emboss/> is present-means-true (ON), a display-only run toggle that
/// adds/removes no characters: accepted and rejected text equal the original.
#[test]
fn onoff_bare_emboss_present_means_true_display_only_text_survives() {
    let body =
        r#"<w:p><w:r><w:rPr><w:emboss/></w:rPr><w:t>Raised letters</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "opensClean — ECMA-376 §17.3.2.13, ISO 29500-1 §17.17.4: a bare CT_OnOff child \
         element with no @val is valid; <w:emboss/> in rPr opens without repair. Issues: {:?}",
        report.issues
    );

    let doc = Document::parse(&b).expect("parse");
    assert_eq!(
        doc.read_accepted().expect("read_accepted").to_text().trim(),
        "Raised letters",
        "acceptTextEquals — ECMA-376 §17.3.2.13, ISO 29500-1 §17.7.3: emboss is a display-only \
         toggle; turning it on changes relief rendering, never the stored characters."
    );
    assert_eq!(
        doc.read_rejected().expect("read_rejected").to_text().trim(),
        "Raised letters",
        "rejectTextEquals — ECMA-376 §17.3.2.13, ISO 29500-1 §22.9.2.7: no tracked change is \
         present and emboss carries no content; reject-all reproduces the same verbatim text."
    );
}

