/// widowControl @val="off" is the ST_OnOff false literal: the property is
/// explicitly OFF. The model-driven serializer must re-emit an explicit-off
/// toggle, never a bare present-means-true element (which Word reads as ON).
#[test]
fn widow_control_val_off_is_off_not_flipped_on() {
    let body = r#"<w:p><w:pPr><w:widowControl w:val="off"/></w:pPr><w:r><w:t>line</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "opensClean — ISO 29500-1 §17.3.1.44, §17.17.4 + transitional s_ST_OnOff = xsd:boolean | \
         ST_OnOff1{{on,off}}: val=\"off\" is a schema-valid false literal; Word opens without \
         repair. Issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);
    // xmlRegex: <w:widowControl[^>]*w:val="(0|false|off)" — translated to a
    // scoped contains check over the widowControl start-tag (no regex dev-dep).
    let tag = start_tag(&xml, "<w:widowControl");
    let has_explicit_off = tag.as_deref().map(tag_has_explicit_off);
    assert_eq!(
        has_explicit_off,
        Some(true),
        "xmlRegex <w:widowControl[^>]*w:val=\"(0|false|off)\" — ISO 29500-1 §17.3.1.44, §17.17.4: \
         val=\"off\" means the property is explicitly OFF, so the re-serialized toggle must carry \
         an explicit-off val. stemma's extract_widow_control mis-parses off→ON and emits a bare \
         element, so this FAILS — the divergence we are hunting. Re-emitted tag: {tag:?}"
    );
    assert!(
        !xml.contains("<w:widowControl/>"),
        "xmlOmits <w:widowControl/> — ISO 29500-1 §17.17.4: a bare element is present-means-true \
         (ON). An author who wrote val=\"off\" must never have the toggle re-emitted as bare ON; \
         that flips the explicit off-intent. Re-serialized XML: {xml}"
    );
}

/// keepNext @val="off" is the ST_OnOff false literal: explicitly OFF, re-emitted
/// as an explicit-off form (the correct-behaviour sibling of widowControl).
#[test]
fn keep_next_val_off_round_trips_as_explicit_off() {
    let body =
        r#"<w:p><w:pPr><w:keepNext w:val="off"/></w:pPr><w:r><w:t>a</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "opensClean — ISO 29500-1 §17.17.4: val=\"off\" is a valid ST_OnOff false literal; Word \
         opens without repair. Issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);
    let tag = start_tag(&xml, "<w:keepNext");
    let has_explicit_off = tag.as_deref().map(tag_has_explicit_off);
    assert_eq!(
        has_explicit_off,
        Some(true),
        "xmlRegex <w:keepNext[^>]*w:val=\"(0|false|off)\" — ISO 29500-1 §17.17.4: val=\"off\" is \
         explicitly-off; the model-driven serializer must re-emit keepNext with an explicit-off \
         val, not flip it to a bare ON element. Re-emitted tag: {tag:?}"
    );
    assert!(
        !xml.contains("<w:keepNext/>"),
        "xmlOmits <w:keepNext/> — ISO 29500-1 §17.17.4: a bare keepNext is present-means-true ON; \
         an author-off keepNext must not be re-emitted as bare ON. XML: {xml}"
    );
}

