/// Run bold toggle @val="off" is the ST_OnOff false literal: bold explicitly
/// suppressed. The serializer must re-emit an explicit-off run toggle, never a
/// bare element (= ON). Display-only: accept/reject text unchanged.
#[test]
fn run_toggle_bold_val_off_serializes_explicit_off() {
    let body =
        r#"<w:p><w:r><w:rPr><w:b w:val="off"/></w:rPr><w:t>plain</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "opensClean — ISO 29500-1 §17.3.2.1, §17.17.4: val=\"off\" is a valid ST_OnOff false \
         literal on a run toggle; Word opens without repair. Issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);
    // Scope the val check to the <w:b …> tag. The bold run-mark serializes as
    // "<w:b " (with attrs) or "<w:b/>"; avoid matching <w:body>, <w:bCs>, etc.
    let tag = start_tag(&xml, "<w:b ").or_else(|| start_tag(&xml, "<w:b/"));
    let has_explicit_off = tag.as_deref().map(tag_has_explicit_off);
    assert_eq!(
        has_explicit_off,
        Some(true),
        "xmlRegex <w:b[^>]*w:val=\"(0|false|off)\" — ISO 29500-1 §17.17.4: b val=\"off\" is \
         explicitly-off; emit_mark_value must re-serialize it as an explicit-off run toggle, not \
         as bare ON or dropped. Re-emitted bold tag: {tag:?}"
    );
    assert!(
        !xml.contains("<w:b/>"),
        "xmlOmits <w:b/> — ISO 29500-1 §17.17.4: a bare <w:b/> is present-means-true ON; an \
         author-off bold must never be re-emitted as bare ON. XML: {xml}"
    );
}

