/// Strict ST_OnOff = xsd:boolean only: the canonical lexicals 1/0 (and
/// true/false) must open clean; a display-only bold toggle set ON (val="1") or
/// OFF (val="0") removes no characters, so accept text is verbatim.
#[test]
fn onoff_strict_only_boolean_lexicals_open_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:b w:val="1"/></w:rPr><w:t>strict bold one</w:t></w:r><w:r><w:rPr><w:b w:val="0"/></w:rPr><w:t>strict bold zero</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "opensClean — ISO 29500-1 §22.9.2.7, §17.17.4; strict ST_OnOff = union(xsd:boolean): 1 \
         and 0 are the canonical boolean lexicals valid under both strict and transitional; \
         stemma must accept both without a validation error. Issues: {:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted");
    assert_eq!(
        accepted.to_text().trim(),
        "strict bold onestrict bold zero",
        "acceptTextEquals — ISO 29500-1 §17.17.4: b is a display-only toggle; whether ON (val=1) \
         or OFF (val=0) it adds/removes no characters, so accepting changes leaves both run \
         texts verbatim."
    );
}
